-- 트랜잭션 수준 읽기 일관성 설정
SET TRANSACTION ISOLATION LEVEL SERIALIZABLE;
-- 이후 모든 쿼리는 이 트랜잭션 시작 시점의 일관된 데이터를 조회
SELECT * FROM employees WHERE department_id = 10;
-- COMMIT 또는 ROLLBACK으로 트랜잭션 종료
COMMIT;

INSERT INTO employees (employee_id, first_name, last_name, email, hire_date, job_id)
VALUES (9001, 'John', 'Doe', 'JDOE', SYSDATE, 'IT_PROG');
SAVEPOINT sp_after_insert;

UPDATE employees SET salary = 50000 WHERE employee_id = 9001;
SAVEPOINT sp_after_update;

DELETE FROM employees WHERE employee_id = 100;
-- 실수를 깨닫고 DELETE만 롤백
ROLLBACK TO SAVEPOINT sp_after_update;
-- INSERT와 UPDATE는 유지된 상태
COMMIT;

-- 현재 RETENTION 보장 모드 확인
SELECT tablespace_name, contents, retention
FROM dba_tablespaces
WHERE contents = 'UNDO';

-- GUARANTEE 모드로 변경
ALTER TABLESPACE undotbs1 RETENTION GUARANTEE;

-- NOGUARANTEE로 복원
-- ALTER TABLESPACE undotbs1 RETENTION NOGUARANTEE;
